var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배, 이것 좀 보세요. 인터넷에서 어딜 가나 펠리세트 이야기뿐이에요.","JPN":"ミナ先輩、これ見てください。ネットのどこを見てもフェリセットの話ばかりです。","ENG":"Look, Mina. Félicette is all over the internet!","TWN":"米娜前輩，你看這個。現在網路上到處都是費莉塞特的發言。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇겠지. 생방송에서 그런 식으로 저질렀으니까.","JPN":"当然だよ。生放送であんな風にやらかしたんだから。","ENG":"Of course she is. She said those words on live TV.","TWN":"想也知道，誰叫她在直播中大放厥詞。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그걸 무마하는 사장님 인맥도 신기하긴 하지만….","JPN":"それを収める社長の人脈も不思議だけど……","ENG":"It's amazing how Boss uses his connections to cover it up, though...","TWN":"不過老闆竟然能把這件事壓下來，看來老闆的人脈也是很驚人……"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"운이 좋았지. 알파트릭스가 협찬사였으니.","JPN":"運がよかったのさ。アルファトリックスがスポンサーだったからな。","ENG":"We were lucky that Alphatrix was the sponsor.","TWN":"只能說是運氣好，剛好阿爾法崔克斯是贊助方。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하긴…. 거기 그룹 회장님이랑 알고 지내는 사이였지?","JPN":"まあ、確かに……そのグループの会長と知り合いだったよね？","ENG":"Oh, right... He knows the President.","TWN":"也是……你和那個集團的會長是認識的吧？"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분해요! 분해서 참을 수가 없어요, 선배!","JPN":"悔しいです！　悔しくてたまりません、先輩！","ENG":"I can't take it anymore! It's so unfair!","TWN":"很生氣欸！我太生氣啦！前輩！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트 때문에 제가 부른 펜릴 소대 테마송은 완전 묻혀 버렸다구요!","JPN":"フェリセットのせいで、私が歌ったフェンリル小隊のテーマソングは完全に無視されちゃったんですよ！","ENG":"Because of Félicette, my Fenrir Squad theme song was completely forgotten!","TWN":"費莉塞特害我唱的芬里爾小隊主題曲都被剪掉咧！"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……묻혀서 다행이야. 정말로.","JPN":"……無視されてよかった。本当に。","ENG":"...I am so glad that it did.","TWN":"……真是萬幸。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"미안하게 됐어. 당분간은 다들 밤길 조심해.","JPN":"悪いな。しばらくはみんな、夜道は気をつけてくれよ。","ENG":"I'm sorry about this. In the meantime, keep an eye out when you're outdoors.","TWN":"對不起，這段時間大家夜裡出門都小心點。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그릴 파티도 언더그라운드 출신이라 뒤에서 하는 짓이 좀 지저분하거든.","JPN":"グリルパーティーもアンダーグラウンド出身だから、裏でちょっと汚いことしてるんだよ。","ENG":"Grill Party also started from the Underground. They do some sketchy things behind the curtains.","TWN":"格里爾派提也是出身於地下世界，做事的手段有點骯髒。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그건 걱정하지 않아도 돼요.","JPN":"それは心配しなくて大丈夫よ。","ENG":"Don't worry about it.","TWN":"不用擔心。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 잘난 1, 2 소대로 예선에서 탈락하면 회사부터 간수해야 할 테니까요.","JPN":"その自慢の第1、第2小隊が予選落ちしたら、まず会社から守らないといけなくなるだろうから。","ENG":"They'll be busy trying to save their company when their stuck-up squads fail to make it past qualifiers.","TWN":"如果那個囂張的第1和第2小隊在預賽中被淘汰，他們就得先給公司一個交代。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트는 참 생각이 독하네요. 피도 눈물도 없어요.","JPN":"フェリセットって怖いこと考えるんですね。血も涙もありません。","ENG":"You can be really heartless at times, Félicette. So cold-blooded.","TWN":"費莉塞特的想法好狠毒，真是冷血無情。"},"stage":{"bg":"DORMITORY_1","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 다들 주목.","JPN":"はい、みんな注目。","ENG":"All right. Attention, everyone.","TWN":"來，全員注意！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이제 예선전 강행군도 막바지야.","JPN":"予選の強行軍も大詰めよ。","ENG":"Qualifiers are coming to an end.","TWN":"現在預賽的賽程也已經接近尾聲。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이번 상대만 이기면 본선 진출 여부는 그릴 파티와의 경기에 달려 있어.","JPN":"次の相手にさえ勝てれば、本選進出の可否はグリルパーティーとの試合にかかってる。","ENG":"If we beat our next opponent, our match against Grill Party will determine whether we make it to the elimination rounds or not.","TWN":"這場打贏後，能否進入決賽的關鍵，就取決於我們和格里爾派提的比賽結果。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우선 코치님 의견대로 노엘을 함께 움직이게 한 건 성과가 좋아.","JPN":"まずはコーチの意見どおり、ノエルを一緒に動かしたのはいい成果をあげたわ。","ENG":"First things first, it was a good idea to move with Noelle, just as Coach said.","TWN":"首先，我們聽從教練的意見，和洛艾兒一起行動的成績還是不錯的。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};